class Solution {
public:
    string reverseOnlyLetters(string s) {
        string letters;
        for (char c : s) {
            if (isalpha(c)) {
                letters += c;
            }
        }
        reverse(letters.begin(), letters.end());
        int k = 0;
        for (int i = 0; i < s.size(); ++i) {
            if (isalpha(s[i])) {
                s[i] = letters[k++];
            }
        }
        return s;
    }
};

